const body = $input.first().json.body;
const platform = body.platform || 'both';
let fbText = body.text;
let igText = body.text;
if (platform === 'both') {
  const fbMatch = body.text.match(/===\s*FACEBOOK\s*===([\s\S]*?)(?:===\s*INSTAGRAM\s*===|$)/i);
  const igMatch = body.text.match(/===\s*INSTAGRAM\s*===([\s\S]*?)(?:===\s*FACEBOOK\s*===|$)/i);
  if (fbMatch && fbMatch[1].trim()) fbText = fbMatch[1].trim();
  if (igMatch && igMatch[1].trim()) igText = igMatch[1].trim();
}
return [{ json: { ...body, fbText, igText, publishFacebook: platform === 'facebook' || platform === 'both', publishInstagram: platform === 'instagram' || platform === 'both' } }];

// Determine if this is an image or text post and call the correct Facebook Graph API endpoint
const data = $('Route Platform').first().json;
const pageId = data.fbPageId;
const token = data.facebookToken;
const text = data.fbText;
const imageUrl = data.imageUrl;

let result;
if (imageUrl) {
  // Image post via /{page-id}/photos
  const res = await fetch(`https://graph.facebook.com/v19.0/${pageId}/photos`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ url: imageUrl, message: text, access_token: token })
  });
  result = await res.json();
} else {
  // Text post via /{page-id}/feed
  const res = await fetch(`https://graph.facebook.com/v19.0/${pageId}/feed`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: text, access_token: token })
  });
  result = await res.json();
}

return [{ json: result }];

const results = { facebook: null, instagram: null };
const errors = [];
try {
  const fb = $('Facebook — Post').first()?.json;
  if (fb && (fb.id || fb.post_id)) {
    results.facebook = { success: true, postId: fb.id || fb.post_id };
  } else if (fb?.error) {
    errors.push('Facebook: ' + JSON.stringify(fb.error));
  }
} catch(e) {}
try {
  const ig = $('IG — Publish').first()?.json;
  if (ig && ig.id) {
    results.instagram = { postId: ig.id, success: true };
  } else if (ig?.error) {
    errors.push('Instagram: ' + JSON.stringify(ig.error));
  }
} catch(e) {}
const success = !!(results.facebook || results.instagram);
return [{ json: { success, results, errors: errors.length > 0 ? errors : undefined } }];
